class Solution:
    def kthRemainingInteger(self, nums, queries):
        ans = []
        for l, r, k in queries:
            removed = set(x for x in nums[l:r + 1] if x % 2 == 0)
            count = 0
            val = 0
            while True:
                val += 2
                if val in removed:
                    continue
                count += 1
                if count == k:
                    break
            ans.append(val)
        return ans

