import bisect

class Solution:
    def kthRemainingInteger(self, nums: list[int], queries: list[list[int]]) -> list[int]:
        n = len(nums)
        prefix_even = [0] * (n + 1)
        for i in range(n):
            prefix_even[i + 1] = prefix_even[i] + (1 if nums[i] % 2 == 0 else 0)

        def removed_le(x, l, r):
            pos = bisect.bisect_right(nums, x) - 1
            hi = min(pos, r)
            if hi < l:
                return 0
            return prefix_even[hi + 1] - prefix_even[l]

        ans = []
        for l, r, k in queries:
            lo, hi = 1, 2 * (k + (r - l + 1) + 2)
            while lo < hi:
                mid = (lo + hi) // 2
                removed = removed_le(mid, l, r)
                rank = mid // 2 - removed
                if rank >= k:
                    hi = mid
                else:
                    lo = mid + 1
            ans.append(lo)
        return ans

