var kthRemainingInteger = function(nums, queries) {
    const n = nums.length;
    const prefixEven = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixEven[i + 1] = prefixEven[i] + (nums[i] % 2 === 0 ? 1 : 0);
    }
    function bisectRight(x) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (nums[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    function removedLe(x, l, r) {
        const pos = bisectRight(x) - 1;
        const hi = Math.min(pos, r);
        if (hi < l) return 0;
        return prefixEven[hi + 1] - prefixEven[l];
    }
    const ans = [];
    for (const [l, r, k] of queries) {
        let lo = 1, hi = 2 * (k + (r - l + 1) + 2);
        while (lo < hi) {
            const mid = Math.floor((lo + hi) / 2);
            const removed = removedLe(mid, l, r);
            const rank = Math.floor(mid / 2) - removed;
            if (rank >= k) hi = mid; else lo = mid + 1;
        }
        ans.push(lo);
    }
    return ans;
};
